mapper.select:
SELECT grade_level as gradeLevel, COUNT(1) as count, ROUND( COUNT(1) * 100.0 / ( SELECT COUNT(1) FROM edu_evaluation WHERE target_teacher_id = #{teacherId} AND is_valid = 1 ), 1 ) as percentage FROM edu_evaluation WHERE target_teacher_id = #{teacherId} AND is_valid = 1
AND semester = #{semester}
GROUP BY grade_level ORDER BY grade_level

SELECT t.teacher_no as teacherNo, t.name as teacherName, col.college_name as collegeName, AVG(e.total_score) as avgScore, COUNT(e.id) as evaluatorCount, ( SELECT grade_level FROM edu_evaluation WHERE target_teacher_id = t.id GROUP BY grade_level ORDER BY COUNT(1) DESC LIMIT 1 ) as gradeLevel FROM edu_teacher t JOIN edu_college col ON t.college_id = col.id LEFT JOIN edu_evaluation e ON e.target_teacher_id = t.id AND e.is_valid = 1
AND t.id = #{teacherId}
AND e.semester = #{semester}
GROUP BY t.id ORDER BY avgScore DESC

SELECT COUNT(DISTINCT e.target_teacher_id) as teacherCount, COUNT(e.id) as totalCount, ROUND(AVG(e.total_score), 1) as avgScore, ROUND( SUM(CASE WHEN e.total_score >= 90 THEN 1 ELSE 0 END) * 100.0 / COUNT(1), 1 ) as excellentRate FROM edu_evaluation e JOIN edu_teacher t ON e.target_teacher_id = t.id WHERE e.is_valid = 1
AND t.college_id = #{collegeId}
AND e.semester = #{semester}

SELECT total_score
FROM edu_evaluation
WHERE target_teacher_id = #{teacherId}
    AND is_valid = 1

    AND semester = #{semester}

ORDER BY total_score
